class Solution {
public:
    int minDays(int n) {
        int days = 0;
        while (n > 1) {
            if (n % 3 == 0) {
                n = n / 3;
            } else if (n % 2 == 0) {
                n = n / 2;
            } else {
                n = n - 1;
            }
            days++;
        }
        return days + 1;
    }
};
